const webhook = $('Unipile - Connexion acceptee').item.json.body;
const profile = $('Unipile - Profil prospect').item.json;
const posts = $('Unipile - Posts prospect').item.json;

const postTexts = (posts.items || [])
  .slice(0, 3)
  .map(p => p.text || p.content || '')
  .filter(t => t && t.length > 20)
  .join('\n---\n');

const lines = [
  'Nom: ' + webhook.user_full_name,
  'Poste: ' + (profile.headline || profile.occupation || ''),
  'Entreprise: ' + (profile.company_name || profile.company || ''),
  'Localisation: ' + (profile.location || ''),
];

if (postTexts) {
  lines.push('Publications recentes:');
  lines.push(postTexts);
}

const profileSummary = lines.filter(l => l && !l.endsWith(': ')).join('\n');

return {
  account_id: webhook.account_id,
  linkedin_id: webhook.user_provider_id,
  full_name: webhook.user_full_name,
  linkedin_url: webhook.user_profile_url,
  profile_picture_url: webhook.user_picture_url,
  occupation: profile.headline || profile.occupation || '',
  company_name: profile.company_name || profile.company || '',
  location: profile.location || '',
  profile_summary: profileSummary,
};

