const config = $('Supabase - Config client').item.json;

const delayMin = config.response_delay_min_minutes ?? 30;
const delayMax = config.response_delay_max_minutes ?? 45;
const activeStart = config.active_hours_start ?? 9;
const activeEnd = config.active_hours_end ?? 19;
const activeDays = config.active_days ?? [1, 2, 3, 4, 5];
const timezone = config.timezone ?? 'Europe/Paris';

const delayMinutes = Math.floor(Math.random() * (delayMax - delayMin + 1)) + delayMin;
let target = DateTime.now().setZone(timezone).plus({ minutes: delayMinutes });

let i = 0;
while (i < 14) {
  const h = target.hour;
  const day = target.weekday;
  if (activeDays.includes(day) && h >= activeStart && h < activeEnd) break;
  if (!activeDays.includes(day) || h >= activeEnd) {
    target = target.plus({ days: 1 }).set({ hour: activeStart, minute: 0, second: 0, millisecond: 0 });
  } else {
    target = target.set({ hour: activeStart, minute: 0, second: 0, millisecond: 0 });
  }
  i++;
}

return [{ json: { message: $json.message, scheduled_send_at: target.toUTC().toISO() } }];
